import React from 'react';

const Dashboard = () => {
    const appointments = [
        { id: 1, doctor: 'Dr. Smith', date: '2024-07-01', time: '10:00 AM' },
        { id: 2, doctor: 'Dr. Johnson', date: '2024-07-05', time: '2:00 PM' },
    ];

    return (
        <div className="min-h-screen p-6 bg-gray-100 text-gray-800">
            {/* Header */}
            <h1 className="text-3xl font-bold mb-8 text-center text-green-700">Dashboard</h1>

            {/* Stats Cards */}
            <div className="grid grid-cols-1 sm:grid-cols-3 gap-4 mb-10">
                <div className="bg-white p-4 rounded shadow text-center">
                    <h2 className="text-sm text-gray-600 mb-1">Total Appointments</h2>
                    <p className="text-2xl font-semibold text-green-600">{appointments.length}</p>
                </div>
                <div className="bg-white p-4 rounded shadow text-center">
                    <h2 className="text-sm text-gray-600 mb-1">Upcoming</h2>
                    <p className="text-2xl font-semibold text-blue-600">{appointments.length}</p>
                </div>
                <div className="bg-white p-4 rounded shadow text-center">
                    <h2 className="text-sm text-gray-600 mb-1">Notifications</h2>
                    <p className="text-2xl font-semibold text-yellow-600">0</p>
                </div>
            </div>

            {/* Appointments List */}
            <div className="bg-white p-5 rounded shadow">
                <h2 className="text-xl font-semibold mb-4">Upcoming Appointments</h2>
                {appointments.length === 0 ? (
                    <p className="text-gray-500">No upcoming appointments.</p>
                ) : (
                    <ul className="space-y-4">
                        {appointments.map((appt) => (
                            <li key={appt.id} className="border p-4 rounded bg-gray-50">
                                <p className="text-base font-medium text-gray-700">Doctor: {appt.doctor}</p>
                                <p className="text-sm text-gray-600">Date: {appt.date}</p>
                                <p className="text-sm text-gray-600">Time: {appt.time}</p>
                            </li>
                        ))}
                    </ul>
                )}
            </div>
        </div>
    );
};

export default Dashboard;
